// Initialize conversation memory and context
const userId = $('Agent Input').first().json.userId || 'default';
const currentMessage = $('Agent Input').first().json.message;
const timestamp = new Date().toISOString();

// Get existing conversation history
let conversationHistory = [];
try {
  const memoryData = $input.first().json;
  if (memoryData && typeof memoryData === 'string') {
    conversationHistory = JSON.parse(memoryData);
  } else if (Array.isArray(memoryData)) {
    conversationHistory = memoryData;
  }
} catch (error) {
  console.log('No existing memory or error parsing:', error);
}

// Add current message to history
conversationHistory.push({
  role: 'user',
  content: currentMessage,
  timestamp: timestamp
});

// Keep only last 10 exchanges to manage context window
if (conversationHistory.length > 20) {
  conversationHistory = conversationHistory.slice(-20);
}

// Analyze message intent
const intent = analyzeIntent(currentMessage);

function analyzeIntent(message) {
  const lowerMsg = message.toLowerCase();

  if (lowerMsg.includes('weather') || lowerMsg.includes('temperature') || lowerMsg.includes('forecast')) {
    return 'weather';
  }
  if (lowerMsg.includes('search') || lowerMsg.includes('find') || lowerMsg.includes('look up')) {
    return 'search';
  }
  if (lowerMsg.includes('calculate') || lowerMsg.includes('math') || /\d+[+\-*/]\d+/.test(lowerMsg)) {
    return 'calculation';
  }
  if (lowerMsg.includes('remind') || lowerMsg.includes('schedule') || lowerMsg.includes('appointment')) {
    return 'reminder';
  }
  if (lowerMsg.includes('email') || lowerMsg.includes('send message')) {
    return 'communication';
  }
  return 'conversation';
}

return {
  userId: userId,
  currentMessage: currentMessage,
  conversationHistory: conversationHistory,
  intent: intent,
  timestamp: timestamp,
  needsTools: intent !== 'conversation'
};

// Simple calculator for the AI agent
const message = $('Process Memory & Intent').first().json.currentMessage;

function calculateExpression(expr) {
  try {
    // Extract mathematical expression
    const mathPattern = /([0-9+\-*/.() ]+)/g;
    const matches = expr.match(mathPattern);

    if (matches && matches.length > 0) {
      // Use Function constructor for safe evaluation (basic expressions only)
      const sanitized = matches[0].replace(/[^0-9+\-*/.() ]/g, '');
      const result = Function('"use strict"; return (' + sanitized + ')')();
      return {
        expression: sanitized,
        result: result,
        success: true
      };
    }
    return { success: false, error: 'No valid mathematical expression found' };
  } catch (error) {
    return { success: false, error: error.message };
  }
}

const calculation = calculateExpression(message);

return {
  toolResult: calculation,
  toolType: 'calculation'
};

// Merge tool results back into the main flow
const memoryData = $('Process Memory & Intent').first().json;
let toolResult = null;
let toolType = null;

// Check which tool was used
if ($input.all().length > 0) {
  const toolData = $input.first().json;

  // Weather tool result
  if (toolData.weather) {
    toolResult = {
      location: toolData.name,
      temperature: toolData.main.temp,
      description: toolData.weather[0].description,
      humidity: toolData.main.humidity
    };
    toolType = 'weather';
  }
  // Calculator tool result
  else if (toolData.toolResult) {
    toolResult = toolData.toolResult;
    toolType = toolData.toolType;
  }
}

return {
  ...memoryData,
  toolResult: toolResult,
  toolType: toolType
};

parameters.messages:
={{ 
  const history = $json.conversationHistory || [];
  const toolResult = $json.toolResult;
  const toolType = $json.toolType;

  let systemPrompt = `You are an intelligent AI agent with access to tools and memory. You can:
- Remember previous conversations
- Use weather data when requested
- Perform calculations
- Provide helpful and contextual responses

You have a friendly, professional personality and always try to be helpful.`;

  if (toolResult) {
    if (toolType === 'weather') {
      systemPrompt += `\n\nWeather data available: Location: ${toolResult.location}, Temperature: ${toolResult.temperature}°C, Conditions: ${toolResult.description}, Humidity: ${toolResult.humidity}%`;
    } else if (toolType === 'calculation') {
      systemPrompt += `\n\nCalculation result: ${toolResult.expression} = ${toolResult.result}`;
    }
  }

  const messages = [
    { role: 'system', content: systemPrompt }
  ];

  // Add conversation history (last 10 exchanges)
  const recentHistory = history.slice(-10);
  messages.push(...recentHistory);

  return messages;
}}

