// Process AI response and update memory
const aiResponse = $input.first().json.choices[0].message.content;
const memoryData = $('Merge Tool Results').first().json;
const userId = memoryData.userId;
const timestamp = new Date().toISOString();

// Add AI response to conversation history
const updatedHistory = [...memoryData.conversationHistory];
updatedHistory.push({
  role: 'assistant',
  content: aiResponse,
  timestamp: timestamp,
  toolUsed: memoryData.toolType || null
});

// Prepare response
const response = {
  success: true,
  message: aiResponse,
  userId: userId,
  timestamp: timestamp,
  conversationId: `conversation_${userId}`,
  toolUsed: memoryData.toolType,
  tokensUsed: $input.first().json.usage?.total_tokens || 0,
  intent: memoryData.intent
};

return {
  response: response,
  memoryKey: `conversation_${userId}`,
  memoryValue: JSON.stringify(updatedHistory),
  conversationHistory: updatedHistory
};

